def _sha256_file(path: Path) -> Optional[str]:
    """Return hex SHA-256 of *path*, or None if the file doesn't exist."""
    if not path.is_file():
        return None
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            h.update(chunk)
    return h.hexdigest()


